		<!-- ── Header ─────────────────────────────────────────────────────────── -->
		{#if headerMode !== "none"}
			<Sidebar.Header>
				<Sidebar.Menu>
					<Sidebar.MenuItem>
						{#if headerMode === "brand"}
							<Sidebar.MenuButton size="lg">
								{#snippet child({ props })}
									<a href={BASE} {...props}>
										<div
											class="bg-sidebar-primary text-sidebar-primary-foreground flex aspect-square size-8 items-center justify-center rounded-lg"
										>
											<IconPlaceholder
