		requestAnimationFrame(() => {
			if (!sda && !manualExpanded) applyFallback();
			compensate(anchor);
			requestAnimationFrame(() => {
				compensate(anchor);
				document.documentElement.style.scrollBehavior = prev;
			});
		});
	}

	function toTop() {
		window.scrollTo({ top: 0, behavior: "smooth" });
	}
